parameters.jsCode:
const bancoDados = $getWorkflowStaticData('global');
const clientId = $('Telegram Trigger').first().json.message.chat.id;

if (!bancoDados.usuario) {
  bancoDados.usuario = {};
}

bancoDados.usuario[clientId] = {
  endereco: 'Rua X',
  numeroPedidos: 0,
  pedidos: [],
  pagamento: 'nenhum'
  //**Para o pagamento usar cartaoOnline; cartaoPresencial; dinheiro; pix.
};

return bancoDados;

